-- S5-05 merchant accept/reject transaction functions.
create or replace function private.finish_merchant_alert(p_order_id uuid,p_actor uuid) returns public.merchant_order_alerts language plpgsql security definer set search_path='' as $$ declare a public.merchant_order_alerts; begin select * into a from public.merchant_order_alerts where order_id=p_order_id for update; if not found then raise exception 'merchant alert not found' using errcode='P0017'; end if; update public.merchant_order_alerts set alert_status='ACKNOWLEDGED',first_sent_at=coalesce(first_sent_at,statement_timestamp()),acknowledged_at=coalesce(acknowledged_at,statement_timestamp()),acknowledged_by=coalesce(acknowledged_by,p_actor),failure_reason=null where id=a.id returning * into a; return a; end $$;
create or replace function public.accept_merchant_order(p_actor uuid,p_order_id uuid,p_preparation_minutes integer) returns jsonb language plpgsql security definer set search_path='' as $$ declare o public.orders; a public.merchant_order_alerts; replay boolean:=false; begin if p_preparation_minutes<1 or p_preparation_minutes>240 then raise exception 'invalid preparation time' using errcode='22023'; end if; select ord.* into o from public.orders ord join public.shops s on s.id=ord.shop_id where ord.id=p_order_id and s.merchant_id=p_actor for update of ord; if not found then raise exception 'merchant order not found' using errcode='P0017'; end if; if o.status='MERCHANT_ACCEPTED' then if o.merchant_preparation_minutes<>p_preparation_minutes then raise exception 'merchant decision payload conflict' using errcode='P0020'; end if; replay:=true; elsif o.status<>'WAITING_FOR_MERCHANT' then raise exception 'merchant order state invalid' using errcode='P0019'; end if; select * into a from public.merchant_order_alerts where order_id=o.id for update; if a.expires_at<=statement_timestamp() and not replay then raise exception 'merchant response expired' using errcode='P0018'; end if; if not replay then update public.orders set merchant_preparation_minutes=p_preparation_minutes where id=o.id; select * into o from private.transition_order_state(o.id,'MERCHANT_ACCEPTED',p_actor,'MERCHANT',null,'Merchant accepted the full order'); a:=private.finish_merchant_alert(o.id,p_actor); perform private.enqueue_outbox_event('order.merchant.accepted','ORDER',o.id,jsonb_build_object('orderId',o.id,'shopId',o.shop_id,'preparationMinutes',p_preparation_minutes,'acceptedAt',o.accepted_at),o.accepted_at,o.accepted_at); else a:=private.finish_merchant_alert(o.id,p_actor); end if; return jsonb_build_object('orderId',o.id,'orderNumber',o.order_number,'status',o.status,'alertStatus',a.alert_status,'merchantPreparationMinutes',o.merchant_preparation_minutes,'acceptedAt',o.accepted_at,'cancelledAt',o.cancelled_at,'cancellationReasonCode',o.cancellation_reason_code,'cancellationNote',o.cancellation_note,'reservationsReleased',0,'replayed',replay); end $$;
create or replace function public.reject_merchant_order(p_actor uuid,p_order_id uuid,p_reason_code text,p_order_item_id uuid default null,p_note text default null) returns jsonb language plpgsql security definer set search_path='' as $$ declare o public.orders; a public.merchant_order_alerts; r record; released integer:=0; replay boolean:=false; begin if p_reason_code not in ('OUT_OF_STOCK','SIZE_UNAVAILABLE','COLOUR_UNAVAILABLE','DAMAGED_ITEM','INVENTORY_MISMATCH','ITEM_NOT_FOUND','SHOP_BUSY','SHOP_CLOSING','OTHER') then raise exception 'invalid rejection reason' using errcode='22023'; end if; if p_reason_code='OTHER' and nullif(btrim(p_note),'') is null then raise exception 'rejection note required' using errcode='22023'; end if; select ord.* into o from public.orders ord join public.shops s on s.id=ord.shop_id where ord.id=p_order_id and s.merchant_id=p_actor for update of ord; if not found then raise exception 'merchant order not found' using errcode='P0017'; end if; if o.status='CANCELLED' and o.cancellation_reason_code=p_reason_code and o.cancellation_note is not distinct from nullif(btrim(p_note),'') then replay:=true; elsif o.status<>'WAITING_FOR_MERCHANT' then raise exception 'merchant order state invalid' using errcode='P0019'; end if; select * into a from public.merchant_order_alerts where order_id=o.id for update; if a.expires_at<=statement_timestamp() and not replay then raise exception 'merchant response expired' using errcode='P0018'; end if; if not replay then if p_order_item_id is not null and not exists(select 1 from public.order_items where id=p_order_item_id and order_id=o.id) then raise exception 'merchant order not found' using errcode='P0017'; end if; insert into public.merchant_order_issues(order_id,order_item_id,issue_type,description,reported_by) values(o.id,p_order_item_id,p_reason_code,nullif(btrim(p_note),''),p_actor); for r in select id from public.inventory_reservations where order_id=o.id and status='ACTIVE' order by id for update loop perform public.release_customer_cart_reservation(r.id,'Merchant rejected order: '||p_reason_code,p_actor); released:=released+1; end loop; update public.orders set cancellation_reason_code=p_reason_code,cancellation_note=nullif(btrim(p_note),'') where id=o.id; select * into o from private.transition_order_state(o.id,'CANCELLED',p_actor,'MERCHANT',p_reason_code,coalesce(nullif(btrim(p_note),''),'Merchant rejected the full order')); a:=private.finish_merchant_alert(o.id,p_actor); perform private.enqueue_outbox_event('order.merchant.rejected','ORDER',o.id,jsonb_build_object('orderId',o.id,'shopId',o.shop_id,'reasonCode',p_reason_code,'orderItemId',p_order_item_id,'reservationsReleased',released,'cancelledAt',o.cancelled_at),o.cancelled_at,o.cancelled_at); else a:=private.finish_merchant_alert(o.id,p_actor); end if; return jsonb_build_object('orderId',o.id,'orderNumber',o.order_number,'status',o.status,'alertStatus',a.alert_status,'merchantPreparationMinutes',o.merchant_preparation_minutes,'acceptedAt',o.accepted_at,'cancelledAt',o.cancelled_at,'cancellationReasonCode',o.cancellation_reason_code,'cancellationNote',o.cancellation_note,'reservationsReleased',released,'replayed',replay); end $$;
revoke all on function public.accept_merchant_order(uuid,uuid,integer),public.reject_merchant_order(uuid,uuid,text,uuid,text) from public,anon,authenticated; grant execute on function public.accept_merchant_order(uuid,uuid,integer),public.reject_merchant_order(uuid,uuid,text,uuid,text) to service_role;
